if (!function_exists('kbtRenderToolIcon')) {
    /**
     * Render a Lucide tool icon by slug.
     * @param string $slug             Icon slug (e.g. 'keyboard', 'mouse', 'sparkles')
     * @param string|null $categoryId  Category ID used as second-chance fallback
     *                                  (keyboard|mouse|display|camera|audio|utility|gaming).
     */
    function kbtRenderToolIcon($slug, $categoryId = null) {
        $map = kbtToolIconMap();
        if ($slug !== '' && isset($map[$slug])) return $map[$slug];
        $catToSlug = [
            'keyboard' => 'keyboard',
            'mouse'    => 'mouse',
            'display'  => 'screen',
            'camera'   => 'camera',
            'audio'    => 'headphones',
            'utility'  => 'wrench',
            'gaming'   => 'gamepad',
        ];
        if ($categoryId !== null && isset($catToSlug[$categoryId]) && isset($map[$catToSlug[$categoryId]])) {
            return $map[$catToSlug[$categoryId]];
        }
        return '<svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="3" width="18" height="18" rx="3"/></svg>';
    }
}
